"use strict";(globalThis.webpackChunkdrpd_docs=globalThis.webpackChunkdrpd_docs||[]).push([[687],{5694(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","href":"/drpd/docs/","label":"About Dr. PD","docId":"intro","unlisted":false},{"type":"link","href":"/drpd/docs/important-warnings","label":"Important warnings and safety precautions","docId":"important-warnings","unlisted":false},{"type":"category","label":"Quickstart","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/drpd/docs/quickstart/overview","label":"Get started in 5 minutes (or less)","docId":"quickstart/overview","unlisted":false},{"type":"link","href":"/drpd/docs/quickstart/connecting-dr-pd","label":"Connecting Dr. PD to your computer or tablet","docId":"quickstart/connecting-dr-pd","unlisted":false},{"type":"link","href":"/drpd/docs/quickstart/pairing-device","label":"Pairing Dr. PD with your computer or tablet","docId":"quickstart/pairing-device","unlisted":false},{"type":"link","href":"/drpd/docs/quickstart/testing-usb-source","label":"Testing a USB-PD source","docId":"quickstart/testing-usb-source","unlisted":false}],"href":"/drpd/docs/category/quickstart"},{"type":"category","label":"How to\u2026","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/drpd/docs/how-to/observing-connection","label":"Observing a USB connection","docId":"how-to/observing-connection","unlisted":false},{"type":"link","href":"/drpd/docs/how-to/operating-as-sink","label":"Operating Dr. PD as a sink","docId":"how-to/operating-as-sink","unlisted":false},{"type":"link","href":"/drpd/docs/how-to/testing-usb-cable","label":"Testing a USB-C cable","docId":"how-to/testing-usb-cable","unlisted":false},{"type":"link","href":"/drpd/docs/how-to/testing-usb-sink","label":"Testing a USB sink device","docId":"how-to/testing-usb-sink","unlisted":false},{"type":"link","href":"/drpd/docs/how-to/chacterizing-device","label":"Characterizing USB-PD source and sinks","docId":"how-to/chacterizing-device","unlisted":false},{"type":"link","href":"/drpd/docs/how-to/capturing-messages","label":"Capturing USB-PD messages","docId":"how-to/capturing-messages","unlisted":false},{"type":"link","href":"/drpd/docs/how-to/protection-mechanisms","label":"Using Dr. PD\'s protection mechanisms","docId":"how-to/protection-mechanisms","unlisted":false},{"type":"link","href":"/drpd/docs/how-to/using-triggers","label":"Using triggers and the sync output","docId":"how-to/using-triggers","unlisted":false}],"href":"/drpd/docs/category/how-to"}]},"docs":{"how-to/capturing-messages":{"id":"how-to/capturing-messages","title":"Capturing USB-PD messages","description":"In either Observer or Sink mode, Dr. PD can capture and log USB-PD messages. This can be useful both for debugging purposes and to understand how a particular device behaves.","sidebar":"tutorialSidebar"},"how-to/chacterizing-device":{"id":"how-to/chacterizing-device","title":"Characterizing USB-PD source and sinks","description":"Dr. PD can be used to characterize the behavior of a USB-PD device to understand how it behaves in different scenarios, and to identify any issues or anomalies in its behavior. This can be useful both for debugging purposes and to understand how a particular device behaves.","sidebar":"tutorialSidebar"},"how-to/observing-connection":{"id":"how-to/observing-connection","title":"Observing a USB connection","description":"In Observer Mode, Dr. PD can be used to observe and analyze the USB-PD communication between two USB-C devices without interfering with the connection. This is useful for debugging and understanding the behavior of USB-PD devices, as well as for learning about the USB-PD protocol.","sidebar":"tutorialSidebar"},"how-to/operating-as-sink":{"id":"how-to/operating-as-sink","title":"Operating Dr. PD as a sink","description":"In addition to observer mode, Dr. PD can also be used in Sink Mode, where it acts as a USB-PD sink device that can be powered by a compatible source.","sidebar":"tutorialSidebar"},"how-to/protection-mechanisms":{"id":"how-to/protection-mechanisms","title":"Using Dr. PD\'s protection mechanisms","description":"The USB-PD protocol includes a set of safety mechanisms that are designed to protect both the source and sink devices from damage in case of abnormal conditions, such as overvoltage, overcurrent, or short circuits. These have their limitations, but are normally \u201cgood enough\u201d for most applications.","sidebar":"tutorialSidebar"},"how-to/testing-usb-cable":{"id":"how-to/testing-usb-cable","title":"Testing a USB-C cable","description":"Coming soon\u2026","sidebar":"tutorialSidebar"},"how-to/testing-usb-sink":{"id":"how-to/testing-usb-sink","title":"Testing a USB sink device","description":"Coming soon\u2026","sidebar":"tutorialSidebar"},"how-to/using-triggers":{"id":"how-to/using-triggers","title":"Using triggers and the sync output","description":"Dr. PD features a sync output on the back panel that can be used to synchronize external devices with specific events within a USB-PD connection. For example, you can connect an oscilloscope to both the CC and sync output to visualize the precise timing of a device\'s signalling, identify runt pulses, or measure the duration of specific events.","sidebar":"tutorialSidebar"},"important-warnings":{"id":"important-warnings","title":"Important warnings and safety precautions","description":"Dr. PD is designed to help you explore the world of USB-PD in a safe and controlled way, but it\'s important to remember that USB-PD devices can deliver high levels of power, and that there is always a risk of damage to your devices or to Dr. PD itself if you are not careful when testing.","sidebar":"tutorialSidebar"},"intro":{"id":"intro","title":"About Dr. PD","description":"Dr. PD is an open-source USB Power Delivery analyzer and programmable sink for","sidebar":"tutorialSidebar"},"quickstart/connecting-dr-pd":{"id":"quickstart/connecting-dr-pd","title":"Connecting Dr. PD to your computer or tablet","description":"Dr. PD connects to your computer or tablet using a micro-USB cable. The device is powered and controlled through this connection, which also allows it to send captured data to the host software.","sidebar":"tutorialSidebar"},"quickstart/overview":{"id":"quickstart/overview","title":"Get started in 5 minutes (or less)","description":"Connecting Dr. PD to your computer and getting your first USB-PD capture is quick and easy. This guide will walk you through the steps to get up and running in no time.","sidebar":"tutorialSidebar"},"quickstart/pairing-device":{"id":"quickstart/pairing-device","title":"Pairing Dr. PD with your computer or tablet","description":"In order to use Dr. PD, you need to pair it with the control software. This is a one-time process that establishes a secure connection between the device and your browser; after pairing, the device will automatically reconnect to the control software whenever it is plugged in.","sidebar":"tutorialSidebar"},"quickstart/testing-usb-source":{"id":"quickstart/testing-usb-source","title":"Testing a USB-PD source","description":"One of the many uses of Dr. PD is to test and characterize USB-PD sources such as chargers, power banks, and USB-C ports on laptops.","sidebar":"tutorialSidebar"}}}}')}}]);